import { ReactComponent as AssistantIcon } from '@/assets/svg/assistant.svg';
import { MessageType } from '@/constants/chat';
import {
  IProcessTrace,
  IReference,
  IReferenceChunk,
} from '@/interfaces/database/chat';
import classNames from 'classnames';
import { memo, useCallback, useEffect, useMemo, useState } from 'react';

import {
  useFetchDocumentInfosByIds,
  useFetchDocumentThumbnailsByIds,
} from '@/hooks/document-hooks';
import { IRegenerateMessage, IRemoveMessageById } from '@/hooks/logic-hooks';
import { cn } from '@/lib/utils';
import { IMessage } from '@/pages/chat/interface';
import MarkdownContent from '@/pages/chat/markdown-content';
import { Avatar, Flex, Space } from 'antd';
import {
  BrainCircuit,
  ChevronDown,
  ChevronUp,
  CircleCheck,
  Loader2,
  Search,
  Sparkles,
  Target,
} from 'lucide-react';
import { ReferenceDocumentList } from '../next-message-item/reference-document-list';
import { InnerUploadedMessageFiles } from '../next-message-item/uploaded-message-files';
import { useTheme } from '../theme-provider';
import { AssistantGroupButton, UserGroupButton } from './group-button';
import styles from './index.less';

interface IProps extends Partial<IRemoveMessageById>, IRegenerateMessage {
  item: IMessage;
  reference: IReference;
  loading?: boolean;
  sendLoading?: boolean;
  visibleAvatar?: boolean;
  nickname?: string;
  avatar?: string;
  avatarDialog?: string | null;
  clickDocumentButton?: (documentId: string, chunk: IReferenceChunk) => void;
  index: number;
  showLikeButton?: boolean;
  showLoudspeaker?: boolean;
  showProcessTrace?: boolean;
}

type TraceStep = {
  key: string;
  title: string;
  detail: string;
  status: 'done' | 'running' | 'pending' | 'failed';
};

const TRACE_STAGE_META = [
  {
    key: 'thinking',
    title: '模型思考',
    icon: BrainCircuit,
    details: [
      '解析问题意图与关键实体',
      '结合对话历史补全上下文',
      '识别回答边界与输出格式',
    ],
  },
  {
    key: 'retrieval',
    title: '检索召回',
    icon: Search,
    details: [
      '向知识库发起语义召回',
      '融合关键词与向量检索',
      '收集候选片段并去重',
    ],
  },
  {
    key: 'filtering',
    title: '筛选重排',
    icon: Target,
    details: [
      '按相关性和置信度重排',
      '筛除低质量和重复内容',
      '保留高价值证据片段',
    ],
  },
  {
    key: 'answering',
    title: '回答生成',
    icon: Sparkles,
    details: [
      '融合证据并组织答案结构',
      '进行事实一致性检查',
      '生成最终自然语言回复',
    ],
  },
];

const createSeed = (text: string) => {
  let seed = 0;
  for (let i = 0; i < text.length; i += 1) {
    seed = (seed * 31 + text.charCodeAt(i)) >>> 0;
  }
  return seed || 1;
};

const nextSeed = (seed: number) => (seed * 1664525 + 1013904223) >>> 0;

const pickBySeed = (seed: number, list: string[]) =>
  list[seed % Math.max(1, list.length)];

const getRunningTraceStageIndex = (
  elapsedMs: number,
  phaseDurations: number[],
  answeringStageIndex: number,
) => {
  let total = 0;
  for (let index = 0; index < phaseDurations.length; index += 1) {
    total += phaseDurations[index];
    if (elapsedMs < total) {
      return index;
    }
  }
  return answeringStageIndex;
};

const buildMockTrace = (
  messageId: string,
  loading: boolean,
  elapsedMs: number,
) => {
  let seed = createSeed(messageId);
  const retrieved = 12 + (seed % 37);
  seed = nextSeed(seed);
  const reranked = 4 + (seed % 9);
  seed = nextSeed(seed);
  const used = Math.max(2, Math.min(6, 2 + (seed % 5)));
  seed = nextSeed(seed);
  const thinkingDelay = 450 + (seed % 550);
  seed = nextSeed(seed);
  const retrievalDelay = 500 + (seed % 700);
  seed = nextSeed(seed);
  const rerankDelay = 450 + (seed % 650);
  const phaseDurations = [thinkingDelay, retrievalDelay, rerankDelay];
  const answeringStageIndex = TRACE_STAGE_META.findIndex(
    (item) => item.key === 'answering',
  );
  const runningStageIndex = getRunningTraceStageIndex(
    elapsedMs,
    phaseDurations,
    answeringStageIndex,
  );

  const steps: TraceStep[] = TRACE_STAGE_META.map((item, index) => {
    seed = nextSeed(seed);
    const randomDetail = pickBySeed(seed, item.details);
    let status: TraceStep['status'] = 'done';
    if (loading) {
      if (index < runningStageIndex) {
        status = 'done';
      } else if (index === runningStageIndex) {
        status = 'running';
      } else {
        status = 'pending';
      }
    }
    return {
      key: item.key,
      title: item.title,
      detail: randomDetail,
      status,
    };
  });

  const traceStatus: IProcessTrace['status'] = loading
    ? 'running'
    : 'completed';
  return {
    mode: 'mock',
    status: traceStatus,
    steps,
    summary: `召回 ${retrieved} 条候选 · 重排 ${reranked} 条 · 采用 ${used} 条证据`,
  };
};

const MessageItem = ({
  item,
  reference,
  loading = false,
  avatar,
  avatarDialog,
  sendLoading = false,
  clickDocumentButton,
  index,
  removeMessageById,
  regenerateMessage,
  showLikeButton = true,
  showLoudspeaker = true,
  visibleAvatar = true,
  showProcessTrace = false,
}: IProps) => {
  const { theme } = useTheme();
  const isAssistant = item.role === MessageType.Assistant;
  const isUser = item.role === MessageType.User;
  const [traceExpanded, setTraceExpanded] = useState(false);
  const [traceStartedAt, setTraceStartedAt] = useState<number | null>(null);
  const [traceNow, setTraceNow] = useState(() => Date.now());
  const { data: documentList, setDocumentIds } = useFetchDocumentInfosByIds();
  const { data: documentThumbnails, setDocumentIds: setIds } =
    useFetchDocumentThumbnailsByIds();

  const referenceDocumentList = useMemo(() => {
    return reference?.doc_aggs ?? [];
  }, [reference?.doc_aggs]);

  const handleRegenerateMessage = useCallback(() => {
    regenerateMessage?.(item);
  }, [regenerateMessage, item]);

  useEffect(() => {
    setTraceExpanded(false);
    setTraceStartedAt(null);
    setTraceNow(Date.now());
  }, [item.id]);

  useEffect(() => {
    if (loading && traceStartedAt === null) {
      setTraceStartedAt(Date.now());
    }
    if (!loading && traceStartedAt !== null) {
      setTraceStartedAt(null);
    }
  }, [loading, traceStartedAt]);

  useEffect(() => {
    if (!loading) return;
    const timer = window.setInterval(() => {
      setTraceNow(Date.now());
    }, 180);

    return () => window.clearInterval(timer);
  }, [loading]);

  const traceElapsedMs =
    loading && traceStartedAt ? Math.max(0, traceNow - traceStartedAt) : 0;

  const trace = useMemo<IProcessTrace | null>(() => {
    if (item.process_trace) {
      return item.process_trace;
    }
    if (loading) {
      return buildMockTrace(item.id, loading, traceElapsedMs);
    }
    return null;
  }, [item.process_trace, item.id, loading, traceElapsedMs]);

  const currentTraceStatus = useMemo(() => {
    if (!trace) {
      return null;
    }
    const runningStep = trace.steps.find((step) => step.status === 'running');
    if (runningStep) {
      return `${runningStep.title}进行中`;
    }

    const pendingStep = trace.steps.find((step) => step.status === 'pending');
    if (pendingStep) {
      return `${pendingStep.title}等待中`;
    }

    return null;
  }, [trace]);

  const collapsedTraceText = useMemo(() => {
    if (!trace) {
      return '';
    }
    if (traceExpanded) {
      return trace.summary;
    }

    if (loading && currentTraceStatus) {
      return currentTraceStatus;
    }

    return trace.summary;
  }, [traceExpanded, loading, currentTraceStatus, trace]);

  useEffect(() => {
    const ids = item?.doc_ids ?? [];
    if (ids.length) {
      setDocumentIds(ids);
      const documentIds = ids.filter((x) => !(x in documentThumbnails));
      if (documentIds.length) {
        setIds(documentIds);
      }
    }
  }, [item.doc_ids, setDocumentIds, setIds, documentThumbnails]);

  return (
    <div
      className={classNames(styles.messageItem, {
        [styles.messageItemLeft]: item.role === MessageType.Assistant,
        [styles.messageItemRight]: item.role === MessageType.User,
      })}
    >
      <section
        className={classNames(styles.messageItemSection, {
          [styles.messageItemSectionLeft]: item.role === MessageType.Assistant,
          [styles.messageItemSectionRight]: item.role === MessageType.User,
        })}
      >
        <div
          className={classNames(styles.messageItemContent, {
            [styles.messageItemContentReverse]: item.role === MessageType.User,
          })}
        >
          {visibleAvatar &&
            (item.role === MessageType.User ? (
              <Avatar size={40} src={avatar ?? '/favicon-vende.png'} />
            ) : avatarDialog ? (
              <Avatar size={40} src={avatarDialog} />
            ) : (
              <AssistantIcon />
            ))}

          <Flex vertical gap={8} flex={1}>
            <Space>
              {isAssistant ? (
                index !== 0 && (
                  <AssistantGroupButton
                    messageId={item.id}
                    content={item.content}
                    prompt={item.prompt}
                    showLikeButton={showLikeButton}
                    audioBinary={item.audio_binary}
                    showLoudspeaker={showLoudspeaker}
                  ></AssistantGroupButton>
                )
              ) : (
                <UserGroupButton
                  content={item.content}
                  messageId={item.id}
                  removeMessageById={removeMessageById}
                  regenerateMessage={
                    regenerateMessage && handleRegenerateMessage
                  }
                  sendLoading={sendLoading}
                ></UserGroupButton>
              )}

              {/* <b>{isAssistant ? '' : nickname}</b> */}
            </Space>
            {isAssistant && index !== 0 && showProcessTrace && trace && (
              <section className={styles.traceContainer}>
                <div className={styles.traceHeader}>
                  <button
                    className={styles.traceToggle}
                    onClick={() => setTraceExpanded((prev) => !prev)}
                    type="button"
                  >
                    <span className={styles.traceTitle}>运行轨迹</span>
                    <span className={styles.traceSummary}>
                      {collapsedTraceText}
                    </span>
                    {traceExpanded ? (
                      <ChevronUp size={14} />
                    ) : (
                      <ChevronDown size={14} />
                    )}
                  </button>
                </div>
                {traceExpanded && (
                  <div className={styles.traceSteps}>
                    {trace.steps.map((step) => {
                      const stageMeta = TRACE_STAGE_META.find(
                        (x) => x.key === step.key,
                      );
                      const Icon = stageMeta?.icon || Sparkles;
                      return (
                        <div key={step.key} className={styles.traceStep}>
                          <div className={styles.traceStepHead}>
                            <span className={styles.traceStepTitle}>
                              <Icon size={14} />
                              {step.title}
                            </span>
                            {step.status === 'done' && (
                              <span className={styles.traceDone}>
                                <CircleCheck size={14} />
                                已完成
                              </span>
                            )}
                            {step.status === 'running' && (
                              <span className={styles.traceRunning}>
                                <Loader2 size={14} className="animate-spin" />
                                进行中
                              </span>
                            )}
                            {step.status === 'pending' && (
                              <span className={styles.tracePending}>
                                等待中
                              </span>
                            )}
                            {step.status === 'failed' && (
                              <span className={styles.traceFailed}>已降级</span>
                            )}
                          </div>
                          <div className={styles.traceStepDetail}>
                            {step.detail}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </section>
            )}
            <div
              className={cn(
                isAssistant
                  ? theme === 'dark'
                    ? styles.messageTextDark
                    : styles.messageText
                  : styles.messageUserText,
                { '!bg-bg-card': !isAssistant },
              )}
            >
              <MarkdownContent
                loading={loading}
                content={item.content}
                reference={reference}
                clickDocumentButton={clickDocumentButton}
              ></MarkdownContent>
            </div>
            {isAssistant && referenceDocumentList.length > 0 && (
              <ReferenceDocumentList
                list={referenceDocumentList}
              ></ReferenceDocumentList>
            )}
            {isUser && documentList.length > 0 && (
              <InnerUploadedMessageFiles
                files={documentList}
              ></InnerUploadedMessageFiles>
            )}
          </Flex>
        </div>
      </section>
    </div>
  );
};

export default memo(MessageItem);
